document.addEventListener("DOMContentLoaded", function () { const section = document.querySelector(".customer-story-full"); if (!section) return; const track = section.querySelector(".customer-story-track"); const items = section.querySelectorAll(".story-link"); const prevBtn = section.querySelector(".story-prev"); const nextBtn = section.querySelector(".story-next"); if (!track || !items.length || !prevBtn || !nextBtn) return; let index = 0; let resizeTimer; function getVisibleCount() { return window.innerWidth <= 767 ? 1 : 3; } function updateSlider() { const visibleCount = getVisibleCount(); const maxIndex = Math.max(items.length - visibleCount, 0); index = Math.min(Math.max(index, 0), maxIndex); const itemWidth = items[0].getBoundingClientRect().width; track.style.transform = "translate3d(" + (-index * itemWidth) + "px, 0, 0)"; } function debounceResize() { clearTimeout(resizeTimer); resizeTimer = setTimeout(updateSlider, 150); } nextBtn.addEventListener("click", function () { const visibleCount = getVisibleCount(); const maxIndex = Math.max(items.length - visibleCount, 0); index = index < maxIndex ? index + 1 : 0; requestAnimationFrame(updateSlider); }); prevBtn.addEventListener("click", function () { const visibleCount = getVisibleCount(); const maxIndex = Math.max(items.length - visibleCount, 0); index = index > 0 ? index - 1 : maxIndex; requestAnimationFrame(updateSlider); }); window.addEventListener("resize", debounceResize); requestAnimationFrame(updateSlider); });